mapper.select:

where 1 = 1

    and sc.system_channel_code like concat('%', #{systemChannelCode}, '%')


    and sc.system_channel_name like concat('%', #{systemChannelName}, '%')


    and sc.fulfillment_mode = #{fulfillmentMode}


    and sc.standard_carrier_code = #{standardCarrierCode}


    and sc.status = #{status}

order by sc.display_order asc, sc.system_channel_code asc

mapper.insert:
insert into logistics_system_channel(
    system_channel_code, system_channel_name, fulfillment_mode, standard_carrier_code, signature_services, status,
    display_order, create_by, create_time, update_by, update_time, remark
) values (
    #{systemChannelCode}, #{systemChannelName}, #{fulfillmentMode}, #{standardCarrierCode}, #{signatureServices}, #{status},
    #{displayOrder}, #{createBy}, sysdate(), #{updateBy}, sysdate(), #{remark}
)

mapper.select:
select m.*, c.provider_kind, c.connection_name
from logistics_carrier_channel_mapping m
join logistics_carrier_connection c on c.carrier_account_id = m.carrier_account_id
where m.system_channel_code = #{systemChannelCode}
  and m.mapping_id = #{mappingId}
limit 1

mapper.delete:
delete from logistics_carrier_channel_mapping
where system_channel_code = #{systemChannelCode}
  and mapping_id = #{mappingId}

mapper.select:
select *
from logistics_system_channel_warehouse
where system_channel_code = #{systemChannelCode}
  and binding_id = #{bindingId}
limit 1

mapper.delete:
delete from logistics_system_channel_warehouse
where system_channel_code = #{systemChannelCode}
  and binding_id = #{bindingId}
